import React from "react";
import { Link } from "react-router-dom";
import { ROUTES } from "../../constants";
import "./Footer.css";

const Footer = () => {
  return (
    <footer className="footer">
      <div className="container">
        <div className="footer-content">
          <div className="footer-section">
            <h3>G-Bridge</h3>
            <p>Hệ thống quản lý hiện đại và hiệu quả</p>
          </div>
          <div className="footer-section">
            <h4>Liên kết nhanh</h4>
            <ul>
              <li><Link to={ROUTES.HOME}>Trang chủ</Link></li>
              <li><Link to={ROUTES.ABOUT}>Giới thiệu</Link></li>
              <li><Link to={ROUTES.CONTACT}>Liên hệ</Link></li>
            </ul>
          </div>
          <div className="footer-section">
            <h4>Thông tin liên hệ</h4>
            <p>Email: contact@g-bridge.com</p>
            <p>Điện thoại: +84 123 456 789</p>
          </div>
        </div>
        <div className="footer-bottom">
          <p>&copy; 2025 G-Bridge. Tất cả quyền được bảo lưu.</p>
        </div>
      </div>
    </footer>
  );
};

export default Footer;
